pub struct ArchiveConfig {
    pub token_threshold: usize,
    pub force_truncate_limit: usize,
    pub session_id: String,
    pub project_id: Option<String>,
}

impl ArchiveConfig {
    pub fn from_threshold(threshold: usize) -> Self {
        Self {
            token_threshold: threshold,
            force_truncate_limit: (threshold as f32 * HARD_LIMIT_RATIO) as usize,
            session_id: String::new(),
            project_id: None,
        }
    }
}

async fn archive_turns(
    &self,
    session_id: &str,
    turns: Vec<MessageTurn>,
    preset: Option<&PresetRequest>,
) -> Result<ArchiveResult, ArchiveError> {
    let config = if let Some(req) = preset {
        let combined = build_combined_from_request(req)?;
        ArchiveConfig::from_threshold(combined.archive_threshold())
            .with_session(session_id)
    } else {
        ArchiveConfig::from_threshold(FALLBACK_ARCHIVE_THRESHOLD)
            .with_session(session_id)
    };
    let storage = self.create_storage();
    let archiver = Archiver::new(config, storage, session_id, None);
    archiver.archive(turns).await.map_err(ArchiveError::Archive)
}

def calculate_token_estimate(text: str, model_family: str) -> int:
    """Estimate token count using heuristic coefficients."""
    if model_family == 'claude':
        coefficient = 1.05
    elif model_family == 'deepseek':
        coefficient = 1.1
    else:
        coefficient = 1.0
    raw_count = len(text.split())
    return int(raw_count * coefficient)

