async function fetchMemory(sessionId) {
  const response = await fetch(`/api/v1/memory/${sessionId}`);
  if (!response.ok) {
    throw new Error(`Failed to fetch memory: ${response.status}`);
  }
  const data = await response.json();
  return data.summaries.map(s => ({
    hookId: s.hook_id,
    content: s.content,
    timestamp: s.archived_at,
  }));
}

