export class ArchiveEngine {
  private storage: Storage;
  private tokenEstimator?: TokenEstimator;

  constructor(storageRoot: PathLike) {
    this.storage = new LocalStorage(storageRoot);
  }

  async preCompress(
    sessionId: string,
    turns: MessageTurn[],
    estimatedTokens?: number,
  ): Promise<PreCompressResult> {
    const tokens = estimatedTokens ?? this.estimateTokens(turns);
    if (tokens < this.threshold) {
      return { skipped: true };
    }
    return await this.archive(sessionId, turns);
  }
