use std::sync::Arc;
use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ModelRegistry {
    variants: HashMap<String, ModelVariant>,
}

impl ModelRegistry {
    pub fn new() -> Self {
        Self { variants: HashMap::new() }
    }

    pub fn register(&mut self, name: &str, variant: ModelVariant) {
        self.variants.insert(name.to_string(), variant);
    }

    pub fn find(&self, name: &str) -> Option<&ModelVariant> {
        self.variants.get(name)
    }

    pub fn all_variants(&self) -> impl Iterator<Item = (&String, &ModelVariant)> {
        self.variants.iter()
    }
}
