import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import type { MessageTurn, ArchiveResult, PresetConfig } from './types';
import { api } from './api';

export const useMemoryStore = defineStore('memory', () => {
  const sessions = ref<Map<string, MessageTurn[]>>(new Map());
  const currentSession = ref<string | null>(null);
  const loading = ref(false);
  const error = ref<string | null>(null);

  const currentTurns = computed(() => {
    if (!currentSession.value) return [];
    return sessions.value.get(currentSession.value) ?? [];
  });

  async function archive(preset?: PresetConfig): Promise<ArchiveResult | null> {
    if (!currentSession.value) return null;
    const turns = currentTurns.value;
    if (turns.length === 0) return null;

    loading.value = true;
    error.value = null;
    try {
      const result = await api.archive({
        session_id: currentSession.value,
        turns,
        preset,
      });
      sessions.value.set(currentSession.value, []);
      return result;
    } catch (e) {
      error.value = (e as Error).message;
      return null;
    } finally {
      loading.value = false;
    }
  }

  return { sessions, currentSession, currentTurns, loading, error, archive };
});
```

