#!/bin/bash
set -euo pipefail

# MemoryCenter deployment script
# Usage: ./deploy.sh [target]

TARGET="${1:-local}"
PROJECT_ROOT="/opt/memory-center"
SERVICE_NAME="memory-center"

log() {
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] $*"
}

check_prerequisites() {
    command -v cargo >/dev/null || { log "Error: cargo not found"; exit 1; }
    command -v systemctl >/dev/null || { log "Error: systemctl not found"; exit 1; }
}

build() {
    log "Building release binary..."
    cd "$PROJECT_ROOT"
    cargo build --release
}

deploy_local() {
    build
    log "Restarting service..."
    sudo systemctl restart "$SERVICE_NAME"
    sudo systemctl status "$SERVICE_NAME" --no-pager
}

deploy_remote() {
    local host="$1"
    log "Deploying to $host..."
    ssh -T root@"$host" "cd $PROJECT_ROOT && git pull && cargo build --release && systemctl restart $SERVICE_NAME"
}

main() {
    check_prerequisites
    case "$TARGET" in
        local) deploy_local ;;
        remote) deploy_remote "162.211.183.236" ;;
        *) log "Unknown target: $TARGET"; exit 1 ;;
    esac
}

main "$@"
